UPDATE workflow_instance SET state = CASE WHEN #{state} IS NULL THEN state ELSE #{state} END, end_time = CASE WHEN #{endTime} IS NULL THEN end_time ELSE #{endTime} END, context = CASE WHEN #{context} IS NULL THEN context ELSE #{context} END, version = version + 1
, biz_id = #{bizId}
